    --header "Accept-language: en" \
    --data "{
    \"id\": 2,
    \"key\": \"voluptas\",
    \"hardware_id\": \"aut\",
    \"name\": \"dolorum\",
    \"hive_id\": 12,
    \"type\": \"deserunt\",
    \"delete\": true,
    \"last_message_received\": \"expedita\",
    \"firmware_version\": \"eaque\",
    \"hardware_version\": \"cupiditate\",
    \"boot_count\": 1,
    \"measurement_interval_min\": 74078.064,
    \"measurement_transmission_ratio\": 4591.560789,
    \"ble_pin\": \"iusto\",
    \"battery_voltage\": 13740.414976,
    \"next_downlink_message\": \"et\",
    \"last_downlink_result\": \"provident\"
}"
</code></pre></div>


<div class="javascript-example">
    <pre><code class="language-javascript">const url = new URL(
    "beep.test/api/devices/excepturi"
);

