    "Authorization": "Bearer Zahe8Vg6P1bdcfDE436k5av",
    "Content-Type": "application/json",
    "Accept": "application/json",
    "Accept-language": "en",
};

let body = {
    "id": 2,
    "key": "voluptas",
    "hardware_id": "aut",
    "name": "dolorum",
    "hive_id": 12,
    "type": "deserunt",
    "delete": true,
    "last_message_received": "expedita",
