                    <h2 id="apiexportcontroller-GETapi-export">api/export GET
Generate an Excel file with all user data and send by e-mail or as download link</h2>

<p>
<small class="badge badge-darkred">requires authentication</small>
</p>



<span id="example-requests-GETapi-export">
<blockquote>Example request:</blockquote>


<div class="bash-example">
    <pre><code class="language-bash">curl --request GET \
    --get "beep.test/api/export" \
    --header "Authorization: Bearer P6Dc6hega8bZ54vadfVE13k" \
    --header "Content-Type: application/json" \
    --header "Accept: application/json" \
    --header "Accept-language: en" \
    --data "{
    \"groupdata\": false,
    \"sensordata\": false,
    \"link\": true
}"
</code></pre></div>


<div class="javascript-example">
    <pre><code class="language-javascript">const url = new URL(
    "beep.test/api/export"
);

const headers = {
    "Authorization": "Bearer P6Dc6hega8bZ54vadfVE13k",
    "Content-Type": "application/json",
    "Accept": "application/json",
    "Accept-language": "en",
};

let body = {
    "groupdata": false,
    "sensordata": false,
    "link": true
};

fetch(url, {
    method: "GET",
    headers,
    body: JSON.stringify(body),
}).then(response =&gt; response.json());</code></pre></div>

