<small class="badge badge-darkred">requires authentication</small>
</p>



<span id="example-requests-DELETEapi-flashlogs--id-">
<blockquote>Example request:</blockquote>


<div class="bash-example">
    <pre><code class="language-bash">curl --request DELETE \
    "beep.test/api/flashlogs/voluptas?id=14" \
    --header "Authorization: Bearer afkV634acd5bvgE8DeP1Z6h" \
    --header "Content-Type: application/json" \
    --header "Accept: application/json" \
    --header "Accept-language: en" \
    --data "{
    \"block_id\": 4
}"
</code></pre></div>


<div class="javascript-example">
    <pre><code class="language-javascript">const url = new URL(
    "beep.test/api/flashlogs/voluptas"
);

const params = {
    "id": "14",
};
Object.keys(params)
    .forEach(key =&gt; url.searchParams.append(key, params[key]));

const headers = {
    "Authorization": "Bearer afkV634acd5bvgE8DeP1Z6h",
    "Content-Type": "application/json",
    "Accept": "application/json",
    "Accept-language": "en",
};

let body = {
    "block_id": 4
};

fetch(url, {
    method: "DELETE",
    headers,
    body: JSON.stringify(body),
}).then(response =&gt; response.json());</code></pre></div>

