    --get "beep.test/api/sensordefinition" \
    --header "Authorization: Bearer aE51cDfh64gVadZP38bv6ke" \
    --header "Content-Type: application/json" \
    --header "Accept: application/json" \
    --header "Accept-language: en" \
    --data "{
    \"device_id\": 15,
    \"hardware_id\": \"impedit\",
    \"device_hardware_id\": \"velit\",
    \"input_measurement_abbreviation\": \"placeat\",
    \"limit\": 2
}"
</code></pre></div>


